struct Node
{
    int data;
    Node *next;
    Node *prev; // NEW — points to the PREVIOUS node
};

#include <iostream>

using namespace std;

struct Node
{
    int data;
    Node *next;
    Node *prev;
};

class DoublyLinkedList
{
private:
    Node *head;
    Node *tail;

public:
    DoublyLinkedList()
    {
        head = nullptr;
        tail = nullptr;
    }

    void insertAtEnd(int value)
    {
        Node *newNode = new Node{value, nullptr, nullptr};

        if (head == nullptr)
        {
            head = tail = newNode;
            return;
        }

        newNode->prev = tail; // link BACKWARD to the old tail
        tail->next = newNode; // link FORWARD from the old tail
        tail = newNode;       // this node is the new tail
    }

    void printForward()
    {
        Node *current = head;
        while (current != nullptr)
        {
            cout << current->data << " ";
            current = current->next;
        }
        cout << endl;
    }

    void printBackward()
    {
        Node *current = tail;
        while (current != nullptr)
        {
            cout << current->data << " ";
            current = current->prev;
        }
        cout << endl;
    }
};

int main()
{
    DoublyLinkedList list;
    list.insertAtEnd(10);
    list.insertAtEnd(20);
    list.insertAtEnd(30);

    list.printForward();
    list.printBackward();

    return 0;
}

